<template><div class="overlay"><form class="modal" @submit.prevent="submit"><h3>{{t(value?'promptops.datasets.editCase':'promptops.datasets.addCase')}}</h3><label>{{t('promptops.datasets.name')}}<input v-model="name" required maxlength="120"></label><label>{{t('promptops.datasets.tags')}}<input v-model="tagsText"></label><label>{{t('promptops.datasets.variables')}}<textarea v-model="variablesText" class="code" required/></label><label>{{t('promptops.datasets.expectedOutput')}}<textarea v-model="expectedText" class="code"/></label><fieldset><legend>{{t('promptops.datasets.validationRules')}}</legend><label>{{t('promptops.datasets.outputType')}}<select v-model="outputType"><option value="">—</option><option>text</option><option>markdown</option><option>json</option></select></label><label>{{t('promptops.datasets.requiredKeywords')}}<input v-model="containsText"></label><label>{{t('promptops.datasets.forbiddenKeywords')}}<input v-model="notContainsText"></label><label>{{t('promptops.datasets.exactMatch')}}<input v-model="exactMatch"></label><label>{{t('promptops.datasets.jsonFields')}}<input v-model="jsonFieldsText"></label><label>{{t('promptops.datasets.jsonSchema')}}<textarea v-model="schemaText" class="code"/></label></fieldset><p v-if="error" class="error">{{error}}</p><div class="actions"><button type="button" @click="$emit('close')">{{t('promptops.datasets.close')}}</button><button class="primary">{{t('promptops.datasets.save')}}</button></div></form></div></template>
<script setup lang="ts">import{ref}from'vue';import{useI18n}from'vue-i18n';import{validateDatasetTestCase,type DatasetExpectedValidation,type DatasetTestCase,type PromptOpsPromptOutputType}from'@prompt-optimizer/core';const props=defineProps<{datasetId:string;workspaceId:string;value?:DatasetTestCase}>();const emit=defineEmits<{close:[];save:[Omit<DatasetTestCase,'id'|'workspaceId'|'datasetId'|'createdAt'|'updatedAt'>|DatasetTestCase]}>();const{t}=useI18n(),source=props.value;const name=ref(source?.name??''),tagsText=ref(source?.tags?.join(', ')??''),variablesText=ref(JSON.stringify(source?.variables??{},null,2)),expectedText=ref(source?.expectedOutput===undefined?'':typeof source.expectedOutput==='string'?source.expectedOutput:JSON.stringify(source.expectedOutput,null,2)),outputType=ref<PromptOpsPromptOutputType|''>(source?.expectedValidation?.type??''),containsText=ref(source?.expectedValidation?.contains?.join(', ')??''),notContainsText=ref(source?.expectedValidation?.notContains?.join(', ')??''),exactMatch=ref(source?.expectedValidation?.exactMatch??''),jsonFieldsText=ref(source?.expectedValidation?.jsonFieldExists?.join(', ')??''),schemaText=ref(source?.expectedValidation?.jsonSchema?JSON.stringify(source.expectedValidation.jsonSchema,null,2):''),error=ref('');const list=(value:string)=>[...new Set(value.split(',').map(x=>x.trim()).filter(Boolean))];const submit=()=>{try{const variables:unknown=JSON.parse(variablesText.value);let expectedOutput:unknown=expectedText.value;if(outputType.value==='json'&&expectedText.value.trim())expectedOutput=JSON.parse(expectedText.value);const rules:DatasetExpectedValidation={...(outputType.value?{type:outputType.value}:{}),...(list(containsText.value).length?{contains:list(containsText.value)}:{}),...(list(notContainsText.value).length?{notContains:list(notContainsText.value)}:{}),...(exactMatch.value?{exactMatch:exactMatch.value,exactMatchTrim:true}:{}),...(list(jsonFieldsText.value).length?{jsonFieldExists:list(jsonFieldsText.value)}:{}),...(schemaText.value.trim()?{jsonSchema:JSON.parse(schemaText.value)}:{})};const overlap=list(containsText.value).filter(x=>list(notContainsText.value).includes(x));if(overlap.length)throw new Error(`${t('promptops.datasets.requiredKeywords')} / ${t('promptops.datasets.forbiddenKeywords')}`);const now=new Date().toISOString();const candidate:DatasetTestCase=source?{...source,name:name.value.trim(),variables:variables as Record<string,unknown>,expectedOutput,expectedValidation:rules,tags:list(tagsText.value)}:{id:'preview',workspaceId:props.workspaceId,datasetId:props.datasetId,name:name.value.trim(),variables:variables as Record<string,unknown>,expectedOutput,expectedValidation:rules,tags:list(tagsText.value),createdAt:now,updatedAt:now};const result=validateDatasetTestCase(candidate);if(!result.valid)throw new Error(result.issues[0].message);emit('save',source?candidate:{name:candidate.name,variables:candidate.variables,expectedOutput:candidate.expectedOutput,expectedValidation:candidate.expectedValidation,tags:candidate.tags})}catch(cause){error.value=cause instanceof Error?cause.message:String(cause)}}</script>
<style scoped>.overlay{position:fixed;inset:0;background:#0008;display:grid;place-items:center;z-index:30}.modal{width:min(760px,94vw);max-height:90vh;overflow:auto;background:var(--n-color,#fff);padding:22px;border-radius:12px;display:grid;gap:12px}label{display:grid;gap:5px}input,textarea,select{padding:9px;border:1px solid #cbd5e1;border-radius:7px;background:inherit;color:inherit}.code{font-family:monospace;min-height:100px}fieldset{display:grid;gap:10px;border:1px solid #cbd5e1}.actions{display:flex;justify-content:flex-end;gap:8px}.primary{background:#2563eb;color:#fff}.error{color:#b91c1c}</style>
